import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int
) -> None:
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    task_iter = iter(tasks)
    running: set[asyncio.Task[None]] = set()
    stopping = False

    def start_queued_tasks() -> None:
        nonlocal stopping

        while not stopping and len(running) < max_concurrent:
            try:
                task_factory = next(task_iter)
            except StopIteration:
                return

            task = asyncio.create_task(task_factory())
            running.add(task)

    async def cancel_and_drain() -> None:
        if not running:
            return

        for task in running:
            task.cancel()

        await asyncio.gather(*running, return_exceptions=True)

    try:
        while running or not stopping:
            start_queued_tasks()

            if not running:
                break

            done, pending = await asyncio.wait(
                running, return_when=asyncio.FIRST_COMPLETED
            )
            running = pending

            for task in done:
                task.result()

            if not pending and stopping:
                break
    except BaseException:
        stopping = True
        await cancel_and_drain()
        raise
